{"content": "import json, subprocess, socket

# Check if prometheus is accessible
for host in ['prometheus', 'localhost', '127.0.0.1', '172.17.0.1']:
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(2)
        result = s.connect_ex((host, 9090))
        s.close()
        print(f"  {host}:9090 -> {'OPEN' if result == 0 else 'closed'}")
    except Exception as e:
        print(f"  {host}:9090 -> ERROR: {e}")

# Check node-exporter
for host in ['node-exporter', 'localhost', '127.0.0.1']:
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(2)
        result = s.connect_ex((host, 9100))
        s.close()
        print(f"  {host}:9100 -> {'OPEN' if result == 0 else 'closed'}")
    except:
        pass

# Check cadvisor
for host in ['cadvisor', 'localhost', '127.0.0.1']:
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(2)
        result = s.connect_ex((host, 8080))
        s.close()
        print(f"  {host}:8080 -> {'OPEN' if result == 0 else 'closed'}")
    except:
        pass

# Get container network info
print("\n=== Container networks ===")
for name in ['monitoring-prometheus', 'monitoring-cadvisor', 'monitoring-node-exporter']:
    result = subprocess.run(['docker', 'inspect', name], capture_output=True, text=True)
    if result.returncode == 0:
        data = json.loads(result.stdout)
        nets = data[0]['NetworkSettings']['Networks']
        for net_name, net_info in nets.items():
            print(f"  {name}: {net_name} -> {net_info.get('IPAddress', 'N/A')}")
